/**
 * Подтема SddsSbComTheme.Inverse
 */
@Composable
public fun SddsSbComTheme.Inverse(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val currentColors = LocalSddsSbComColors.current
    val overrideColors = currentColors.copyAttrs(InverseColorsOverride)
    val currentGradients = LocalSddsSbComGradients.current
    val overrideGradients = currentGradients.copyAttrs(InverseGradientsOverride)
    SddsSbComTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
